#include<bits/stdc++.h>
#define maxn 2500
using namespace std;
string and_false_th(string A,string B){
	int a[maxn]={0},b[maxn]={0},c[maxn]={0};
	string ans="";
    int len=max(A.length(),B.length());
    for(int i=A.length()-1,j=1;i>=0;i--,j++)a[j]=A[i]-'0';
    for(int i=B.length()-1,j=1;i>=0;i--,j++)b[j]=B[i]-'0';
    for(int i=1;i<=len;i++) {
        c[i]+=a[i]+b[i];
        c[i+1]=c[i]/10;
        c[i]%=10;
    }
    if(c[len+1])len++;
    for(int i=len;i>=1;i--)ans+=char(c[i]+'0');
	return ans;
}
int main(void)
{
	int dodo;
	string coco,aoao="1",bobo="1";
	cin>>dodo;
	for(int i=3;i<=dodo+1;i++){
		coco=and_false_th(aoao,bobo);
		aoao=bobo;
		bobo=coco;
	}
	if(dodo==1)cout<<1;
	else cout<<coco;
	return false;
}
